GRCH37_MESSAGE = """
This file appears to use GRCh37 / Build 37 coordinates.

Please run liftover first to convert the file to GRCh38 before running OPUS.

No report files were created.
"""


def build_parser():
    parser = argparse.ArgumentParser(
        prog="taykit opus",
        description="Generate OPUS reports from raw DNA files.",
        epilog="""
Examples:
  taykit opus mydna.txt
  taykit opus mydna.txt --output-path ./reports

Supported providers:
  - SelfDecode (GRCh38)
  - 23andMe
  - AncestryDNA
  - MyHeritage

Notes:
  - GRCh37 / Build37 files are rejected.
  - Run liftover before processing GRCh37 files.
""",
        formatter_class=argparse.RawDescriptionHelpFormatter,
    )

    parser.add_argument("genetic_file", nargs="?", help="Path to the raw DNA file")

    parser.add_argument("--output-path", help="Folder to write output reports into")

    return parser


def parse_args():
    parser = build_parser()
    args = parser.parse_args()

    if not args.genetic_file:
        parser.print_help()
        sys.exit(1)

    return args


def detect_provider_and_build(file_path: Path):
    """
    Detect provider and genome build.
    """

    header_lines = []

    with file_path.open("r", encoding="utf-8", errors="ignore") as file:
        for _ in range(40):
            line = file.readline()
            if not line:
                break

            header_lines.append(line.strip())

    joined = "\n".join(header_lines).lower()

    # ------------------------------------------------------------------------
    # Ancestry
    # ------------------------------------------------------------------------

    if "ancestrydna raw data download" in joined:
        return {"provider": "AncestryDNA", "build": "GRCh37"}

    # ------------------------------------------------------------------------
    # SelfDecode
    # ------------------------------------------------------------------------

    if "source: selfdecode" in joined:
        if "assembly: grch38" in joined:
            return {"provider": "SelfDecode", "build": "GRCh38"}

        return {"provider": "SelfDecode", "build": "Unknown"}

    # ------------------------------------------------------------------------
    # MyHeritage
    # ------------------------------------------------------------------------

    if "fileformat=myheritage" in joined:
        if "reference=build37" in joined:
            return {"provider": "MyHeritage", "build": "GRCh37"}

        if "reference=build38" in joined:
            return {"provider": "MyHeritage", "build": "GRCh38"}

        return {"provider": "MyHeritage", "build": "Unknown"}

    # ------------------------------------------------------------------------
    # 23andMe
    # ------------------------------------------------------------------------

    if "23andme" in joined:
        if "build 37" in joined:
            return {"provider": "23andMe", "build": "GRCh37"}

        if "build 38" in joined:
            return {"provider": "23andMe", "build": "GRCh38"}

        return {"provider": "23andMe", "build": "Unknown"}

    return {"provider": "Unknown", "build": "Unknown"}


def load_genetic_data(file_path: Path, provider: str):
    """
    Load rsID -> genotype mapping.
    """

    data = {}

    # ------------------------------------------------------------------------
    # SelfDecode / 23AndMe
    # ------------------------------------------------------------------------

    if provider in ["SelfDecode", "23andMe"]:
        with file_path.open("r", encoding="utf-8", errors="ignore") as file:
            for line in file:
                if line.startswith("#"):
                    continue

                parts = line.strip().split("\t")

                if len(parts) < 4:
                    continue

                rsid = parts[0].strip()

                genotype = parts[3].strip().upper()

                if rsid.startswith("GSA-"):
                    rsid = rsid.replace("GSA-", "")

                data[rsid] = genotype

    # ------------------------------------------------------------------------
    # Ancestry
    # ------------------------------------------------------------------------

    elif provider == "AncestryDNA":
        with file_path.open("r", encoding="utf-8", errors="ignore") as file:
            for line in file:
                if line.startswith("#"):
                    continue

                parts = line.strip().split("\t")

                if len(parts) < 5:
                    continue

                rsid = parts[0].strip()

                allele1 = parts[3].strip().upper()
                allele2 = parts[4].strip().upper()

                genotype = allele1 + allele2

                data[rsid] = genotype

    # ------------------------------------------------------------------------
    # MyHeritage
    # ------------------------------------------------------------------------

    elif provider == "MyHeritage":
        with file_path.open("r", encoding="utf-8", errors="ignore") as file:
            reader = csv.reader(file)

            for row in reader:
                if not row:
                    continue

                if row[0].startswith("#"):
                    continue

                if row[0].upper() == "RSID":
                    continue

                if len(row) < 4:
                    continue

                rsid = row[0].replace('"', "").strip()

                genotype = row[3].replace('"', "").strip().upper()

                data[rsid] = genotype

    return data


def generate_matches(genetic_data):
    """
    Match uploaded DNA against OPUS SNPs.
    """

    matches = []

    for rsid, opus in OPUS_LOOKUP.items():
        if rsid not in genetic_data:
            continue

        genotype = genetic_data[rsid]

        risk = opus.get("risk", "").upper()

        matched = risk in genotype

        matches.append(
            {
                "gene": opus.get("gene", ""),
                "rsid": rsid,
                "genotype": genotype,
                "risk": risk,
                "matched": matched,
                "type": opus.get("type", ""),
                "power_score": opus.get("power_score", 0),
                "snp_label": opus.get("snp_label", ""),
            }
        )

    return matches


def write_txt_report(output_file: Path, matches):

    with output_file.open("w", encoding="utf-8") as file:
        file.write("OPUS REPORT\n")
        file.write("=" * 80 + "\n\n")

        for match in matches:
            file.write(
                f"{match['gene']} | "
                f"{match['rsid']} | "
                f"{match['genotype']} | "
                f"Risk={match['risk']} | "
                f"Matched={match['matched']} | "
                f"Power={match['power_score']}\n"
            )


def write_html_report(output_file: Path, matches, provider):

    rows = []

    for match in matches:
        badge = (
            '<span class="badge bg-danger">MATCH</span>'
            if match["matched"]
            else '<span class="badge bg-success">NO MATCH</span>'
        )

        rows.append(f"""
        <tr>
            <td>{html.escape(match["gene"])}</td>
            <td>{html.escape(match["rsid"])}</td>
            <td>{html.escape(match["genotype"])}</td>
            <td>{html.escape(match["risk"])}</td>
            <td>{html.escape(match["type"])}</td>
            <td>{match["power_score"]}</td>
            <td>{badge}</td>
        </tr>
        """)

    html_output = f"""
<!doctype html>
<html>
<head>
    <meta charset="utf-8">
    <title>OPUS Report</title>

    <link
        href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.7/dist/css/bootstrap.min.css"
        rel="stylesheet"
    >
</head>

<body class="bg-light">

<div class="container py-5">

    <h1 class="mb-4">OPUS Report</h1>

    <div class="alert alert-primary">
        Provider: {html.escape(provider)}
    </div>

    <table class="table table-striped table-bordered bg-white">

        <thead class="table-dark">
            <tr>
                <th>Gene</th>
                <th>RSID</th>
                <th>Genotype</th>
                <th>Risk</th>
                <th>Type</th>
                <th>Power</th>
                <th>Status</th>
            </tr>
        </thead>

        <tbody>
            {"".join(rows)}
        </tbody>

    </table>

</div>

</body>
</html>
"""

    with output_file.open("w", encoding="utf-8") as file:
        file.write(html_output)


def run_opus(args):
    input_file = Path(args.genetic_file)

    if not input_file.exists():
        print(f"ERROR: File not found: {input_file}")
        sys.exit(1)

    info = detect_provider_and_build(input_file)

    provider = info["provider"]
    build = info["build"]

    print(f"Detected Provider : {provider}")
    print(f"Detected Build    : {build}")

    if build == "GRCh37":
        print(GRCH37_MESSAGE)
        sys.exit(1)

    if provider == "Unknown":
        print("ERROR: Unsupported or unknown DNA format.")
        sys.exit(1)

    genetic_data = load_genetic_data(input_file, provider)

    print(f"Loaded {len(genetic_data):,} SNPs")

    matches = generate_matches(genetic_data)

    print(f"Matched {len(matches):,} OPUS SNPs")

    if args.output_path:
        output_dir = Path(args.output_path)
    else:
        output_dir = input_file.parent

    output_dir.mkdir(parents=True, exist_ok=True)

    base_name = input_file.stem

    txt_output = output_dir / f"{base_name}_opus.txt"
    html_output = output_dir / f"{base_name}_opus.html"

    write_txt_report(txt_output, matches)
    write_html_report(html_output, matches, provider)

    print()
    print(f"TXT Report  : {txt_output}")
    print(f"HTML Report : {html_output}")


def main(args=None):
    """
    Allows this file to work both ways:

    1. As part of taykit:
       taykit opus sample.txt

    2. Directly:
       python opus.py sample.txt
    """

    if args is None:
        args = parse_args()

    if not getattr(args, "genetic_file", None):
        parser = build_parser()
        parser.print_help()
        sys.exit(1)

    run_opus(args)


if __name__ == "__main__":
    main()
